const lead = $input.first().json;
const prompt = `Analyze this architecture firm for digital readiness:
Business: ${lead.businessName}
Website Score: ${lead.websiteScore}/100
Location: ${lead.city}, ${lead.state}

Provide:
1. Digital SWOT analysis
2. Market position assessment
3. Recommendation for landing page
4. Lead quality score (0-100)

Return JSON: {"swot":{"strengths":[],"weaknesses":[],"opportunities":[],"threats":[]},"marketPosition":"","recommendation":"","leadQualityScore":0}`;
return {lead, prompt};

const aiResp = $input.first().json;
const lead = $('Build Audit Prompt').first().json.lead;
let audit = {swot: {strengths: ['Architecture expertise'], weaknesses: ['Website needs improvement'], opportunities: ['More clients online'], threats: ['Competition']}, marketPosition: 'Small firm', recommendation: 'Invest in professional landing page', leadQualityScore: 50};
try {
  const content = aiResp.choices?.[0]?.message?.content;
  if (content) { const parsed = JSON.parse(content); if (parsed.swot) audit = parsed; }
} catch(e) {}
return {leadId: lead.leadId, businessName: lead.businessName, ...audit, auditedAt: new Date().toISOString()};
